public final class AnalyticsDebugURLSessionDelegate: NSObject, URLSessionTaskDelegate, URLSessionDataDelegate {
    public typealias BodyDecoder = (Data) -> Any?
    private let decodeBody: BodyDecoder?

    private var startTimes: [Int: Date] = [:]
    private let lock = NSLock()

    public init(decodeBody: BodyDecoder? = nil) {
        self.decodeBody = decodeBody
        super.init()
    }

    public func urlSession(_ session: URLSession, task: URLSessionTask, didFinishCollecting metrics: URLSessionTaskMetrics) {
        guard let start = metrics.taskInterval.startDate as Date? else { return }
        lock.lock()
        startTimes[task.taskIdentifier] = start
        lock.unlock()
    }

    public func urlSession(_ session: URLSession, task: URLSessionTask, didCompleteWithError error: Error?) {
        guard let request = task.originalRequest, let url = request.url else { return }
        let method = request.httpMethod ?? "GET"
        let requestId = request.value(forHTTPHeaderField: "X-Request-Id") ?? UUID().uuidString

        let durationMs: Int? = {
            lock.lock()
            defer { lock.unlock() }
            if let start = startTimes.removeValue(forKey: task.taskIdentifier) {
                return Int(Date().timeIntervalSince(start) * 1000.0)
            }
            return nil
        }()

        if let error {
            AnalyticsDebug.trackAPIError(requestId: requestId, url: url, method: method, error: error, statusCode: (task.response as? HTTPURLResponse)?.statusCode, responseBody: nil, durationMs: durationMs)
        } else if let http = task.response as? HTTPURLResponse {
            AnalyticsDebug.trackAPIResponse(requestId: requestId, url: url, statusCode: http.statusCode, headers: http.allHeaderFields, body: nil, durationMs: durationMs)
        }
    }

    public func urlSession(_ session: URLSession, dataTask: URLSessionDataTask, didReceive data: Data) {
        guard let request = dataTask.originalRequest, let url = request.url else { return }
        let requestId = request.value(forHTTPHeaderField: "X-Request-Id") ?? UUID().uuidString
        let statusCode = (dataTask.response as? HTTPURLResponse)?.statusCode ?? -1

        let bodyObj: Any? = decodeBody?(data) ?? SafeSerializer.tryDecodeJSON(data) ?? String(data: data, encoding: .utf8)
        AnalyticsDebug.trackAPIResponse(requestId: requestId, url: url, statusCode: statusCode, headers: (dataTask.response as? HTTPURLResponse)?.allHeaderFields, body: bodyObj, durationMs: nil)
    }
}

