public enum SensitiveDataRedactor {
    private static let sensitiveKeys: Set<String> = [
        "password", "passcode", "secret", "token", "accessToken", "refreshToken", "idToken",
        "authorization", "auth", "cookie", "set-cookie", "session", "apiKey",
        "email", "phone", "ssn", "creditCard", "cardNumber"
    ]

    public static func redact(fields: [String: Any]) -> [String: Any] {
        var out: [String: Any] = [:]
        for (k, v) in fields {
            if isSensitiveKey(k) {
                out[k] = "<redacted>"
            } else {
                out[k] = redact(value: v)
            }
        }
        return out
    }

    private static func redact(value: Any) -> Any {
        if let dict = value as? [String: Any] {
            return redact(fields: dict)
        } else if let dict = value as? [String: String] {
            return redact(fields: dict.mapValues { $0 })
        } else if let arr = value as? [Any] {
            return arr.map { redact(value: $0) }
        } else if let nsDict = value as? NSDictionary {
            var swift: [String: Any] = [:]
            for (k, v) in nsDict {
                if let ks = k as? String {
                    swift[ks] = v
                }
            }
            return redact(fields: swift)
        } else if let nsArr = value as? NSArray {
            return nsArr.map { redact(value: $0) }
        }
        return value
    }

    private static func isSensitiveKey(_ key: String) -> Bool {
        let lowered = key.trimmingCharacters(in: .whitespacesAndNewlines).lowercased()
        if sensitiveKeys.contains(lowered) { return true }
        if lowered.contains("token") { return true }
        if lowered.contains("password") { return true }
        if lowered.contains("secret") { return true }
        if lowered == "authorization" { return true }
        if lowered.contains("email") { return true }
        return false
    }
}

public enum SafeSerializer {
    public static func serialize(_ value: Any, maxBytes: Int) -> String {
        let s: String
        if let str = value as? String {
            s = str
        } else if let data = value as? Data {
            s = String(data: data, encoding: .utf8) ?? "<\(data.count) bytes>"
        } else if JSONSerialization.isValidJSONObject(value) {
            if let data = try? JSONSerialization.data(withJSONObject: value, options: [.prettyPrinted, .sortedKeys]),
               let str = String(data: data, encoding: .utf8) {
                s = str
            } else {
                s = String(describing: value)
            }
        } else {
            s = String(describing: value)
        }

        if let data = s.data(using: .utf8), data.count > maxBytes {
            let prefixBytes = max(0, maxBytes - 64)
            let prefix = String(s.prefix(prefixBytes))
            return prefix + "\n...<truncated \(data.count - prefixBytes) bytes>..."
        }
        return s
    }

    public static func tryDecodeJSON(_ data: Data) -> Any? {
        guard !data.isEmpty else { return nil }
        return try? JSONSerialization.jsonObject(with: data, options: [.fragmentsAllowed])
    }
}

public extension Dictionary where Key == String, Value == Any {
    func compactNils() -> [String: Any] {
        var out: [String: Any] = [:]
        for (k, v) in self {
            if case Optional<Any>.none = v as Any? {
                continue
            }
            if let opt = v as? OptionalProtocol, opt.isNil {
                continue
            }
            out[k] = v
        }
        return out
    }
}

private protocol OptionalProtocol {
    var isNil: Bool { get }
}
extension Optional: OptionalProtocol {
    var isNil: Bool { self == nil }
}